+  }
+
+  #getChat(): MatrixChat {
+    if (!this.#chat) {
+      this.#chat = this.#runtime.createChat(this.#getAdapter(), this.#userName);
+      this.#registerInboundHandlers();
+    }
+
+    return this.#chat;
+  }
+}

