+    },
+    platform: "matrix",
+    status: "active",
+  };
+}
+
+function createMatrixContext(config: ProviderConfig): ProviderContext {
+  return {
+    config,
+    fixture: {
+      env: [],
+      id: "matrix-fixture",
+      inboundMatch: { author: "assistant", nonce: "contains", strategy: "contains" },
+      mode: "roundtrip",
+      provider: "matrix-native",
